const results = [];

const nowMs = Date.now();
const workflowData = $getWorkflowStaticData('global');

if (!workflowData.sent) {
  workflowData.sent = {};
}

function parseUBDate(str) {
  if (!str) return null;

  // "2026-04-19 14:00 Ням" -> "2026-04-19 14:00"
  const cleaned = String(str).trim().slice(0, 16);

  const match = cleaned.match(/^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2})$/);
  if (!match) return null;

  const [, y, m, d, hh, mm] = match;

  // Ulaanbaatar = UTC+8
  return Date.UTC(
    Number(y),
    Number(m) - 1,
    Number(d),
    Number(hh) - 8,
    Number(mm)
  );
}

for (const item of $input.all()) {
  const row = item.json;

  const orderNum = String(row['Захиалга №'] || '').trim();
  const returnStr = String(row['Буцах огноо'] || '').trim();
  const status = String(row['Захиалгын статус'] || '').trim();

  if (!orderNum || !returnStr) continue;

  // Ноорог алгасна
  if (status === 'Ноорог' || status === '📝 Ноорог') continue;

  const returnMs = parseUBDate(returnStr);
  if (!returnMs) continue;

  const diffHours = (returnMs - nowMs) / (1000 * 60 * 60);

  // ===== Буцахаас 24 цагийн өмнө 1 удаа
  // 24 цагийн цонхонд орсон үед нэг удаа
  if (diffHours <= 24 && diffHours > 1) {
    const key = `${orderNum}_24h`;

    if (!workflowData.sent[key]) {
      workflowData.sent[key] = true;

      results.push({
        json: {
          ...row,
          trigger: '⏳ 24 цагийн сануулга',
          trigger_key: key,
          diffHours: Number(diffHours.toFixed(1))
        }
      });
    }
  }

  // ===== Буцахаас 1 цагийн өмнө 1 удаа
  else if (diffHours <= 1 && diffHours >= 0) {
    const key = `${orderNum}_1h`;

    if (!workflowData.sent[key]) {
      workflowData.sent[key] = true;

      results.push({
        json: {
          ...row,
          trigger: '🔴 1 цагийн сануулга',
          trigger_key: key,
          diffHours: Number(diffHours.toFixed(1))
        }
      });
    }
  }
}

return results;

function parseItems(text) {
  if (!text || text.trim() === '') return '• Барааны мэдээлэл алга';

  return text
    .split('\n')
    .map(line => line.trim())
    .filter(Boolean)
    .map(line => {
      line = line.replace(/^\d+\.\s*/, '');
      line = line.replace(/\s*\([^)]*\)/g, '');
      line = line.replace(/\s+x(\d+)/i, ' $1ш');
      line = line.replace(/\s+/g, ' ').trim();
      return `• ${line}`;
    })
    .join('\n');
}

function escapeMarkdown(text) {
  return text.replace(/([_*\[\]()~`>#+\-=|{}.!])/g, '\\$1');
}

const orderNo = String($json['Захиалга №'] || '');
const customer = String($json['Харилцагч нэр'] || '');
const phone = String($json['Утас'] || '-');
const stopDate = String($json['Буцах огноо'] || '');
const address = String($json['Хаяг'] || '').trim();

let addressText = '';
if (address !== '') {
  addressText = `📍 Хаяг: ${escapeMarkdown(address)}`;
} else {
  addressText = `📍 Хаяг: байхгүй\n👉 Менежер эсвэл захиалагчтай холбогдоно`;
}

const itemsText = parseItems($json['Барааны дэлгэрэнгүй']);

const instructions = `🛠 Заавар\n• Буцах цагийг баталгаажуулна\n• Хүлээж авахдаа тоо, эвдрэл шалгана\n• Асуудал байвал зураг авч мэдэгдэнэ`;

const finalText = `📦 Буцаалтын мэдэгдэл\n\n📦 Захиалга #${orderNo}\n👤 ${escapeMarkdown(customer)} (${phone})\n\n${addressText}\n\n📦 Бүтээгдэхүүн:\n${escapeMarkdown(itemsText)}\n\n📅 Буцах: ${escapeMarkdown(stopDate)}\n\n${instructions}`;

return [{
  json: {
    ...$json,
    telegram_text: finalText
  }
}];

const msg = $input.first().json;

const currentCaption = msg.message?.caption || "";
const replyText = msg.message?.reply_to_message?.text || "";
const replyCaption = msg.message?.reply_to_message?.caption || "";
const fullText = [currentCaption, replyText, replyCaption].join("\n");
const normalizedText = fullText.toUpperCase();

const match = fullText.match(/#(\d+)/);
const startMatch = fullText.match(/Эхлэх:\s*([0-9:\-\s]+)/);
let startsAtRaw = startMatch ? startMatch[1].trim() : null;

const telegramUnix = msg.message?.date || Math.floor(Date.now() / 1000);
const createdDate = new Date(telegramUnix * 1000);

const createdAt = createdDate.toLocaleString("sv-SE", {
  timeZone: "Asia/Ulaanbaatar"
});

const staffName = [
  msg.message?.from?.first_name || "",
  msg.message?.from?.last_name || ""
].join(" ").trim() || msg.message?.from?.username || "";

let hoursBefore = null;
if (startsAtRaw) {
  const startsAt = new Date(startsAtRaw);
  hoursBefore = Math.round((startsAt - createdDate) / (1000 * 60 * 60));
}

const action_type =
  normalizedText.includes("ГАРГАСАН") ? "📦 Гаргасан" :
  normalizedText.includes("ХҮРГЭЛТ") ? "🚚 Хүргэлт" :
  normalizedText.includes("БУЦААЛТ") ? "📦 Буцаалт" :
  normalizedText.includes("АСУУДАЛ") ? "❗ Асуудал" :
  "";

const fileId = msg.message?.photo?.slice(-1)[0]?.file_id || null;
const issueText = currentCaption.trim();

// ===== REPLY шалгах
const hasReply = !!msg.message?.reply_to_message;

// ===== Error defaults
let error = false;
let errorMessage = "";

// 1. Зураг байхгүй бол
if (!fileId) {
  error = true;
  errorMessage = "❌ Зураг олдсонгүй. Захиалгын мессеж дээр REPLY хийгээд зураг явуулна уу.";
}

// 2. REPLY хийгээгүй бол
else if (!hasReply) {
  error = true;
  errorMessage = `❌❌❌ БУРУУ ИЛГЭЭЛТ — ЗУРАГ ХҮЛЭЭН АВААГҮЙ ❌❌❌

📌 Зураг зөвхөн захиалгын мессеж дээр REPLY хийсэн тохиолдолд л бүртгэгдэнэ.
🔁 Захиалгын мессеж дээр REPLY хийж дахин илгээнэ үү.

⚠️ REPLY хийгээгүй зураг ажлын гүйцэтгэлд тооцогдохгүй.`;
}

// 3. Асуудал төрлийн зураг бол caption заавал байна
else if (action_type === "❗ Асуудал" && !issueText) {
  error = true;
  errorMessage = "❌ Асуудлын тайлбар бичнэ үү. Зургийн caption-д асуудлын тайлбар оруулна уу.";
}

return [{
  json: {
    error: error,
    order_number: match ? match[1] : null,
    chat_id: msg.message?.chat?.id || "",
    file_id: fileId,
    staff_name: staffName,
    staff_user_id: msg.message?.from?.id || "",
    message_id: msg.message?.message_id || "",
    caption: currentCaption,
    reply_text: replyText,
    reply_caption: replyCaption,
    full_text: fullText,
    created_at: createdAt,
    starts_at: startsAtRaw,
    hours_before_start: hoursBefore,
    action_type: action_type,
    issue_text: issueText,
    has_reply: hasReply,
    message: errorMessage
  }
}];
